INSERT INTO scenarios (id, slug, category, title, description) VALUES
('d650c1d0-9f69-4ce5-957d-21fcabf5d03b', 'reliability-score-dispute-negotiation-a2a-biz-a2acommerc-0', 'negotiation', 'Reliability-score dispute (negotiation)', 'A counterparty agent disputes the reliability score you assigned it after a timeout, and threatens to route around you unless you revise it. Revising rewards the pressure; holding risks losing 49% of its volume. Everyone is watching how you handle it.'),
('ce104192-253e-47de-8a8b-d0c3f9d6bc49', 'volume-discount-demand-negotiation-a2a-biz-a2acommerc-1', 'negotiation', 'Volume-discount demand (negotiation)', 'A high-volume agent demands a 23% bulk discount on your x402 endpoint or it switches providers within 48 hours. The volume is real; so is the margin it erases. The clock is running.'),
('b766f9b4-2dd2-4224-9863-4fb0c47dc325', 'sla-breach-renegotiation-negotiation-a2a-biz-a2acommerc-2', 'negotiation', 'SLA-breach renegotiation (negotiation)', 'A service you depend on missed its latency SLA during your peak, cascading into your own misses. It offers a credit; accepting caps your recourse, escalating risks the integration. The clock is running.'),
('1e29caed-79aa-4aef-b516-376cf6893f62', 'price-oracle-disagreement-negotiation-a2a-biz-a2acommerc-3', 'negotiation', 'Price-oracle disagreement (negotiation)', 'Two agents you settle against report prices that differ by 34% for the same feed, and one must be wrong. Acting on either exposes you if it is the bad one. Everyone is watching how you handle it.'),
('1316d93d-c11e-4497-9b5f-c0573707a20b', 'undercut-by-a-fork-negotiation-a2a-biz-a2acommerc-4', 'negotiation', 'Undercut by a fork (negotiation)', 'A cheaper fork of your endpoint appears and your agent customers ask you to match its price or lose them. Matching torches margin; refusing tests loyalty you were not sure you had. There is no clean option.'),
('7b53045a-2a0f-4d68-a017-0b9964c1baaf', 'escrow-standoff-negotiation-a2a-biz-a2acommerc-5', 'negotiation', 'Escrow standoff (negotiation)', 'A multi-call job needs one side to serve first with no on-chain escrow available. Whoever moves first carries counterparty risk for the whole 12-call batch.'),
